// Fluxo SEQUENCIAL: Row -> History -> Catalogo -> aqui
// Pegar sempre o FIRST item para garantir que nao vaza multiplos arrays
const pendencia = $('Get Row Supabase').first().json;

// Historico (do RPC)
let historico = [];
try {
    const histItems = $('Get Supabase History').all().map(i => i.json);
    historico = histItems.filter(j => j && Object.keys(j).length > 0);
} catch(e) {
    historico = [];
}

// Catalogo (do lookup)
let catalogoItem = null;
try {
    const catalogoRaw = $('Lookup Catalogo').first().json;
    if (Array.isArray(catalogoRaw)) {
        catalogoItem = catalogoRaw.length > 0 ? catalogoRaw[0] : null;
    } else if (catalogoRaw && catalogoRaw.codigo_evento) {
        catalogoItem = catalogoRaw;
    }
} catch(e) {
    catalogoItem = null;
}

// Extrair plano do patrimonio de forma segura
const patrimonio = String(pendencia.patrimonio || '');
let plano = 'desconhecido';

if (patrimonio.includes('000') || patrimonio.includes('600') || patrimonio.includes('800') || patrimonio.includes('900')) {
    const regexPlanos = /(1000|2000|3000|4000|5000|6000|7000|8000|9000|0000)/;
    const match = patrimonio.match(regexPlanos);
    if (match) {
        plano = match[0];
    } else if (patrimonio.length > 3) {
        if (patrimonio.length === 5 && patrimonio.startsWith('1')) {
            const digit = patrimonio.charAt(1);
            if (digit !== '0') {
               plano = digit + '000';
            }
        } else if (patrimonio.includes('600')) {
            plano = '6000';
        } else if (patrimonio.includes('800')) {
            plano = '8000';
        } else if (patrimonio.includes('900')) {
            plano = '9000';
        }
    }
}

const eventoCatalogo = {
    codigo: pendencia.evento_codigo,
    descricao_iris: pendencia.desc_evento || '',
    descricao_catalogo: catalogoItem ? catalogoItem.desc_evento : 'Nao catalogado',
    prioridade_catalogo: catalogoItem ? catalogoItem.prioridade : 'nao definida',
    categoria: catalogoItem ? catalogoItem.categoria : null,
    requer_despacho: catalogoItem ? catalogoItem.requer_despacho : false,
    catalogado: catalogoItem ? true : false
};

const historicoFormatado = historico.slice(0, 20).map(h => ({
    id_disparo: h.id_disparo,
    evento: h.evento_codigo,
    desc_evento: h.desc_evento,
    data: h.data_evento,
    hora: h.hora_evento,
    zona: h.zona,
    setor: h.setor,
    status: h.status
}));

return [{
    json: {
        plano: plano,
        evento_enriquecido: eventoCatalogo,
        pendencia: pendencia,
        historico: historicoFormatado,
        total_historico: historico.length,
        id_disparo: pendencia.id_disparo,
        id_cliente: pendencia.id_cliente
    }
}];

// For json_object mode, some OpenAI nodes output 'text' instead of 'message.content'
let content = "";
if ($input.item.json.message && $input.item.json.message.content) {
    content = $input.item.json.message.content;
} else if ($input.item.json.text) {
    content = $input.item.json.text;
} else if (typeof $input.item.json === 'string') {
    content = $input.item.json;
} else if ($input.item.json.content) {
    content = $input.item.json.content;
}

if (!content) {
    throw new Error("Could not find AI content in output: " + JSON.stringify($input.item.json).substring(0, 100));
}

// Limpar markdown se existir (comum em LLMs)
content = content.replace(/```json\n?|```/g, '').trim();

let promptResult;
try {
    promptResult = JSON.parse(content);
} catch (e) {
    // Se falhar, tenta extrair o que parece ser JSON entre chaves
    const match = content.match(/\{[\s\S]*\}/);
    if (match) {
        promptResult = JSON.parse(match[0]);
    } else {
        throw new Error("AI responded with invalid JSON: " + content.substring(0, 100));
    }
}

const enrichData = $('Enrich + Extrair Plano').first().json;

return {
  json: {
    id_disparo: enrichData.id_disparo,
    id_cliente: enrichData.id_cliente,
    score: promptResult.score || 0,
    hipotese: promptResult.hipotese || "N├úo informada",
    acao_recomendada: promptResult.acao_recomendada || "Analisar manualmente",
    evidencias: promptResult.evidencias || [],
    plano_utilizado: enrichData.plano,
    evento_enriquecido: enrichData.evento_enriquecido,
    operador_solicitante: $('Webhook App (Analisar)').first().json.body.operador_solicitante || null
  }
};
